<template>
	<div class="__c_wi" ref="itemContainer">
        <div class="p">
            <div class="x">
                {{ pTitle }}
            </div>
            <div class="y">
                <p>{{ pIntro }}</p>
            </div>
            <div class="z">
                Stacks: <span>{{ pStacks }} </span>
            </div>
        </div>
        <div class="q" v-if="isLoadImage">
            <div class="x" ref="imgContainer" @scroll="scrollHandler($event)">
                <div class="i" @mousemove.prevent="mouseMoveHandler($event)" @mouseup="mouseUpHandler($event)" @mouseleave="mouseUpHandler($event)" @mousedown="mouseDownHandler($event)">
                    <image-loader v-for="(img,i) in pImages" :key="img" :name="img"  :cssClass="(platform == 1) ? 'img desk' : (platform == 2 ? 'img mobi' : 'img web')" :style="i > 0 ? 'margin-left: 10px' : ''"></image-loader>
                </div>
            </div>
            <div class="y" v-if="platform != 2">
                <b v-for="i in pImages.length" :key="'b_'+i" :class="i == imageIndex ? 'active' : ''" @click="toggleImage(i)"></b>
            </div>
            <div class="y" v-else></div>
        </div>
        <div class="q" v-else>
            <div class="x">
                <div class="i">
                    <image-loader name="" cssClass="img web"></image-loader>
                </div>
            </div>
        </div>
	</div>
</template>

<script>
import ImageLoader from '@/components/ImageLoader.vue';

import 'vue-awesome/icons/square';

export default {
    props: ['pTitle', 'pIntro', 'pStacks', 'pImages', 'platform', 'pIndex', 'scrollMe'],
    components: {
        ImageLoader
    },
    data() {
        return {
            isLoadImage: false,
            startX: 0,
            scrollLeft: 0,
            enableGrab: false,
            imageIndex: 1,
            itemOffsetTop: 0,
        }
    },
    methods: {
        toggleImage(i) {
            this.$refs.imgContainer.scrollLeft = 400*(i-1);
            this.imageIndex = i;
        },
        mouseDownHandler(e) {
            this.startX = e.pageX - this.$refs.imgContainer.offsetLeft;
            this.scrollLeft = this.$refs.imgContainer.scrollLeft;
            this.enableGrab = true;
        },
        mouseMoveHandler(e) {
            if (!this.enableGrab) return;
            const x = e.pageX - this.$refs.imgContainer.offsetLeft;
            const scroll = x - this.startX;
            this.$refs.imgContainer.scrollLeft = this.scrollLeft - scroll;
        },
        mouseUpHandler() {
            this.enableGrab = false;
        },
        scrollHandler(e) {
            const scroll = e.srcElement.scrollLeft;
            this.imageIndex = Math.floor(scroll/400) + 1;
        }
    },
    mounted() {
        this.itemOffsetTop = this.$refs.itemContainer.offsetTop;
        if (this.pIndex < 2)
            this.isLoadImage = true;
    },
    watch: {
        scrollMe(n) {
            if (!this.isLoadImage && ((n+400 ) > this.itemOffsetTop) || this.pIndex < 2) {
                window.setTimeout(() => { this.isLoadImage = true; }, 500);
            }
        }
    }
}
</script>


